  1→import supabase from "./supabase.js";
  2→import GenerateEmbeddings from "../utils/GenerateEmbeddings.js";
  3→
  4→// Canonical topics from onboarding wizard (InterestsStep.jsx)
  5→const CANONICAL_TOPICS = [
  6→    'Poetry', 'Fiction', 'Journals', 'Essays',
  7→    'Philosophy', 'Self-Reflection', 'Creative Nonfiction', 'Short Stories',
  8→    'Science', 'Nature', 'Music', 'Art',
  9→    'Travel', 'Technology', 'Mental Health', 'Spirituality',
 10→];
 11→
 12→// In-memory cache: topic string → embedding array
 13→const topicEmbeddingCache = new Map();
 14→
 15→/**
 16→ * Generate a single embedding from an array of interest strings.
 17→ * Joins them into a comma-separated string and runs through the embedding pipeline.
 18→ */
 19→export const generateInterestsEmbedding = async (interests) => {
 20→    if (!Array.isArray(interests) || interests.length === 0) {
 21→        return null;
 22→    }
 23→
 24→    const joined = interests
 25→        .filter(i => typeof i === 'string' && i.trim())
 26→        .join(', ');
 27→
 28→    if (!joined) return null;
 29→
 30→    return GenerateEmbeddings(joined);
 31→};
 32→
 33→/**
 34→ * Generate an interests embedding for a user and store it on the users table.
 35→ */
 36→export const updateUserInterestsEmbedding = async (userId, interests) => {
 37→    const embedding = await generateInterestsEmbedding(interests);
 38→    if (!embedding) return;
 39→
 40→    const { error } = await supabase
 41→        .from('users')
 42→        .update({ interests_embedding: embedding })
 43→        .eq('id', userId);
 44→
 45→    if (error) {
 46→        console.error(`Failed to update interests_embedding for user ${userId}:`, error.message);
 47→    }
 48→};
 49→
 50→/**
 51→ * Bootstrap topic_embeddings table at server start.
 52→ * Generates embeddings for any missing topics and loads all into the in-memory cache.
 53→ */
 54→export const bootstrapTopicEmbeddings = async () => {
 55→    // Fetch existing topic embeddings
 56→    const { data: existing, error: fetchError } = await supabase
 57→        .from('topic_embeddings')
 58→        .select('topic, embedding');
 59→
 60→    if (fetchError) {
 61→        console.error('Failed to fetch topic_embeddings:', fetchError.message);
 62→        return;
 63→    }
 64→
 65→    const existingTopics = new Set((existing || []).map(r => r.topic));
 66→
 67→    // Load existing into cache
 68→    for (const row of (existing || [])) {
 69→        topicEmbeddingCache.set(row.topic, row.embedding);
 70→    }
 71→
 72→    // Find missing topics
 73→    const missing = CANONICAL_TOPICS.filter(t => !existingTopics.has(t));
 74→
 75→    if (missing.length > 0) {
 76→        console.log(`topic_embeddings: generating ${missing.length} missing embeddings...`);
 77→
 78→        for (const topic of missing) {
 79→            try {
 80→                const embedding = await GenerateEmbeddings(topic);
 81→                if (!embedding) {
 82→                    console.error(`  Failed to generate embedding for topic "${topic}"`);
 83→                    continue;
 84→                }
 85→
 86→                const { error: insertError } = await supabase
 87→                    .from('topic_embeddings')
 88→                    .upsert({ topic, embedding }, { onConflict: 'topic' });
 89→
 90→                if (insertError) {
 91→                    console.error(`  Failed to insert topic "${topic}":`, insertError.message);
 92→                } else {
 93→                    topicEmbeddingCache.set(topic, embedding);
 94→                }
 95→            } catch (err) {
 96→                console.error(`  Error generating embedding for topic "${topic}":`, err.message);
 97→            }
 98→        }
 99→    }
100→
101→    console.log(`topic_embeddings: all topics present (${topicEmbeddingCache.size} cached)`);
102→};
103→
104→/**
105→ * Get the cached embedding for a topic.
106→ * Returns null if not cached (topic was never bootstrapped or failed).
107→ */
108→export const getTopicEmbedding = (topic) => {
109→    return topicEmbeddingCache.get(topic) || null;
110→};
