 1→import supabase from "./supabase.js";
 2→import { getTopicEmbedding } from "./interestEmbeddingService.js";
 3→
 4→const MAX_INTEREST_SECTIONS = 8;
 5→const MIN_POSTS_PER_SECTION = 2;
 6→
 7→/**
 8→ * Get interest-based explore sections for a user.
 9→ * Fetches the user's writing_interests, looks up cached topic embeddings,
10→ * and calls get_interest_posts RPC in parallel for each interest.
11→ */
12→export const getInterestSectionsService = async (userId) => {
13→    if (!userId) {
14→        throw { status: 401, error: 'authentication required' };
15→    }
16→
17→    // Fetch user's writing interests
18→    const { data: userData, error: userError } = await supabase
19→        .from('users')
20→        .select('writing_interests')
21→        .eq('id', userId)
22→        .single();
23→
24→    if (userError) {
25→        console.error('supabase error fetching user interests:', userError.message);
26→        throw { status: 500, error: 'failed to fetch user interests' };
27→    }
28→
29→    const interests = userData?.writing_interests;
30→    if (!Array.isArray(interests) || interests.length === 0) {
31→        return { sections: [] };
32→    }
33→
34→    // Cap at MAX_INTEREST_SECTIONS
35→    const capped = interests.slice(0, MAX_INTEREST_SECTIONS);
36→
37→    // Build queries in parallel — skip interests without a cached embedding
38→    const sectionPromises = capped.map(async (interest) => {
39→        const embedding = getTopicEmbedding(interest);
40→        if (!embedding) {
41→            return null;
42→        }
43→
44→        try {
45→            const { data: posts, error: rpcError } = await supabase.rpc('get_interest_posts', {
46→                p_topic_embedding: embedding,
47→                p_limit: 8,
48→                p_recency_days: 30
49→            });
50→
51→            if (rpcError) {
52→                console.error(`RPC error for interest "${interest}":`, rpcError.message);
53→                return null;
54→            }
55→
56→            if (!posts || posts.length < MIN_POSTS_PER_SECTION) {
57→                return null;
58→            }
59→
60→            return {
61→                interest,
62→                posts: posts.map(row => ({
63→                    id: row.id,
64→                    user_id: row.user_id,
65→                    title: row.title,
66→                    content: row.content,
67→                    post_type: row.post_type,
68→                    created_at: row.created_at,
69→                    views: row.views,
70→                    user_name: row.user_name,
71→                    user_image_url: row.user_image_url,
72→                    user_badge: row.user_badge,
73→                    username: row.username,
74→                    like_count: Number(row.like_count),
75→                    comment_count: Number(row.comment_count),
76→                    bookmark_count: Number(row.bookmark_count),
77→                }))
78→            };
79→        } catch (err) {
80→            console.error(`Error fetching interest posts for "${interest}":`, err?.message || err);
81→            return null;
82→        }
83→    });
84→
85→    const results = await Promise.all(sectionPromises);
86→    const sections = results.filter(Boolean);
87→
88→    return { sections };
89→};
