 1→/**
 2→ * One-time script to generate interests embeddings for existing users.
 3→ * Run: node --env-file=.env server/scripts/backfillInterestEmbeddings.js
 4→ */
 5→import { createClient } from '@supabase/supabase-js';
 6→import GenerateEmbeddings from '../utils/GenerateEmbeddings.js';
 7→
 8→const SUPABASE_URL = process.env.SUPABASE_URL;
 9→const SUPABASE_KEY = process.env.SUPABASE_SERVICE_ROLE || process.env.SUPABASE_SERVICE_ROLE_KEY || process.env.SUPABASE_API_KEY;
10→
11→if (!SUPABASE_URL || !SUPABASE_KEY) {
12→    console.error('Missing SUPABASE_URL or SUPABASE_SERVICE_ROLE_KEY env vars');
13→    process.exit(1);
14→}
15→
16→const supabase = createClient(SUPABASE_URL, SUPABASE_KEY);
17→
18→const run = async () => {
19→    // Fetch users who have writing_interests but no interests_embedding
20→    const { data: users, error } = await supabase
21→        .from('users')
22→        .select('id, writing_interests')
23→        .not('writing_interests', 'is', null)
24→        .is('interests_embedding', null);
25→
26→    if (error) {
27→        console.error('Failed to fetch users:', error.message);
28→        process.exit(1);
29→    }
30→
31→    // Filter to users who actually have a non-empty interests array
32→    const eligible = (users || []).filter(u =>
33→        Array.isArray(u.writing_interests) && u.writing_interests.length > 0
34→    );
35→
36→    if (eligible.length === 0) {
37→        console.log('No users need interest embedding backfill.');
38→        return;
39→    }
40→
41→    console.log(`Found ${eligible.length} users with interests but no embedding.`);
42→
43→    let updated = 0;
44→    let failed = 0;
45→
46→    for (const user of eligible) {
47→        const joined = user.writing_interests
48→            .filter(i => typeof i === 'string' && i.trim())
49→            .join(', ');
50→
51→        if (!joined) {
52→            console.log(`  Skipping user ${user.id} — empty interests after filtering`);
53→            failed++;
54→            continue;
55→        }
56→
57→        const embedding = await GenerateEmbeddings(joined);
58→
59→        if (!embedding || !Array.isArray(embedding) || embedding.length === 0) {
60→            console.error(`  Failed to generate embedding for user ${user.id}`);
61→            failed++;
62→            continue;
63→        }
64→
65→        const { error: updateError } = await supabase
66→            .from('users')
67→            .update({ interests_embedding: embedding })
68→            .eq('id', user.id);
69→
70→        if (updateError) {
71→            console.error(`  Failed to update user ${user.id}:`, updateError.message);
72→            failed++;
73→        } else {
74→            updated++;
75→            console.log(`  User ${user.id} -> embedding (${embedding.length} dims) [${user.writing_interests.join(', ')}]`);
76→        }
77→    }
78→
79→    console.log(`\nDone. Updated: ${updated}, Failed: ${failed}`);
80→};
81→
82→run().catch((err) => {
83→    console.error('Backfill error:', err);
84→    process.exit(1);
85→});
