 272→router.get('/getFollowsData', async(req, res) => {
 273→    const {userId, loggedInUserId} = req.query;
 274→    if(!userId && !loggedInUserId) return res.status(400).json({error: 'userId or loggendUserId is undefined '});
 275→    // console.log(req.query)
 276→    try {
 277→        const followersCountPromise = supabase
 278→        .from('follows')
 279→        .select('*', {count: 'exact', head: true})
 280→        .eq('following_id', userId);
 281→
 282→        const followingCountPromise = supabase
 283→        .from('follows')
 284→        .select('*', {count: 'exact', head: true})
 285→        .eq('follower_id', userId)
 286→
 287→        const isFollowingPromise = supabase
 288→        .from('follows')
 289→        .select('*', {count: 'exact', head: true})
 290→        .eq('follower_id', loggedInUserId)
 291→        .eq('following_id', userId)
 292→
 293→        const [followersCountResult, followingsCountResult, isFollowingResult] = await Promise.all([
 294→            followersCountPromise, followingCountPromise, isFollowingPromise,
 295→        ])
 296→
 297→
 298→        const {count: followersCount, error: errorFollowers } = followersCountResult;
 299→        const {count: followingsCount, error: errorFollowings} = followingsCountResult;
 300→        const {count: isFollowingCount, error: errorIsfollowing} = isFollowingResult;
 301→
 302→        if(errorFollowers || errorFollowings || errorIsfollowing){
 303→            console.error('supabase error while fetching data:', errorFollowers.message, errorFollowings.message, errorIsfollowing.message)
 304→            return res.status(500).json({error: 'failed to fetch data'})
 305→        }
 306→
 307→        return res.status(200).json({
 308→            followersCount: followersCount,
 309→            followingsCount: followingsCount,
 310→            isFollowing: isFollowingCount > 0
 311→        })
 312→
 313→    } catch (error) {
 314→        console.error('Error in Promise.all:', error);
 315→        res.status(500).json({ error: 'An unexpected error occurred' });
 316→    }
 317→
 318→})
