 349→        req.query.limit,
 350→        NOTIFICATION_LIMIT_MIN,
 351→        NOTIFICATION_LIMIT_MAX,
 352→        NOTIFICATION_DEFAULT_LIMIT
 353→    );
 354→
 355→    if(parsedLimit == null){
 356→        return res.status(400).json({error: `limit must be between ${NOTIFICATION_LIMIT_MIN} and ${NOTIFICATION_LIMIT_MAX}`});
 357→    }
 358→
 359→    // Fetch a generous amount from both tables, then merge and paginate
 360→    const fetchLimit = parsedLimit + 1;
 361→
 362→    let journalQuery = supabase
 363→    .from('notifications')
 364→    .select(NOTIFICATION_JOURNAL_SELECT)
 365→    .eq('receiver_id', userId)
 366→    .order('created_at', {ascending: false})
 367→    .order('id', {ascending: false})
 368→    .limit(fetchLimit)
 369→
 370→    let opinionQuery = supabase
 371→    .from('notification_opinions')
 372→    .select(NOTIFICATION_OPINION_SELECT)
 373→    .eq('receiver_id', userId)
 374→    .order('created_at', {ascending: false})
 375→    .order('id', {ascending: false})
 376→    .limit(fetchLimit)
 377→
 378→    if(before){
 379→        journalQuery = journalQuery.lt('created_at', before);
 380→        opinionQuery = opinionQuery.lt('created_at', before);
 381→    }
 382→
 383→    const [journalResult, opinionResult] = await Promise.all([journalQuery, opinionQuery]);
 384→
 385→    if(journalResult.error){
 386→        console.error('error while fetching data from notification table:', journalResult.error);
 387→        return res.status(500).json({error: 'error fetching data from notification table'});
 388→    }
 389→    if(opinionResult.error){
 390→        console.error('error while fetching data from notification_opinions table:', opinionResult.error);
 391→        return res.status(500).json({error: 'error fetching data from notification_opinions table'});
 392→    }
 393→
 394→    const journalNotifs = (journalResult.data || []).map(n => ({...n, source: 'journal'}));
 395→    const opinionNotifs = (opinionResult.data || []).map(n => ({...n, source: 'opinion'}));
 396→
 397→    // Merge and sort by created_at descending
 398→    const merged = [...journalNotifs, ...opinionNotifs]
 399→        .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
 400→
 401→    // Likes/bookmarks lookup only for journal notifications
 402→    const journalIds = [...new Set(
 403→        merged
 404→            .filter((n) => n.source === 'journal')
 405→            .map((n) => n.journal_id)
 406→            .filter(Boolean)
 407→    )];
 408→
 409→    let hasLikedResult = [];
 410→    let hasBookMarkedResult = [];
 411→    if(journalIds.length > 0){
 412→        const [hasLiked, hasBookMarked] = await Promise.all([
 413→            supabase.from('likes').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
 414→            supabase.from('bookmarks').select('journal_id').in('journal_id', journalIds).eq('user_id', userId)
 415→        ]);
 416→
 417→        if(hasLiked.error || hasBookMarked.error){
 418→            console.error('supabase error while fetching data:', hasLiked.error || hasBookMarked.error);
 419→        }
 420→        hasLikedResult = hasLiked.data || [];
 421→        hasBookMarkedResult = hasBookMarked.data || [];
 422→    }
 423→
 424→    const userHasLikedSet = new Set(hasLikedResult.map((likes) => likes.journal_id));
 425→    const userHasBookmarkedSet = new Set(hasBookMarkedResult.map((bookmarks) => bookmarks.journal_id));
 426→
 427→    const formatted = merged.map((notif) => ({
 428→        ...notif,
 429→        hasLiked: notif.source === 'journal' ? userHasLikedSet.has(notif.journal_id) : false,
 430→        hasBookMarked: notif.source === 'journal' ? userHasBookmarkedSet.has(notif.journal_id) : false
 431→    }))
 432→
 433→    const hasMore = formatted.length > parsedLimit;
 434→    const slicedData = hasMore ? formatted.slice(0, parsedLimit) : formatted;
 435→
 436→    return res.status(200).json(
 437→        {
 438→            hasMore: hasMore,
 439→            data: slicedData,
 440→        }
 441→    )
 442→
