651→    const [userLikes, userBookmarks, userReactions] = await Promise.all([
652→        supabase.from('likes').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
653→        supabase.from('bookmarks').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
654→        supabase.from('reactions').select('journal_id, reaction_type').in('journal_id', journalIds).eq('user_id', userId)
655→    ]);
656→
657→    const userHasLikedSet = new Set(userLikes.data?.map(j => j.journal_id) || []);
658→    const userHasBookmarkedSet = new Set(userBookmarks.data?.map(j => j.journal_id) || []);
659→    const userReactionMap = new Map((userReactions.data || []).map(r => [r.journal_id, r.reaction_type]));
660→
661→    await attachRepostSources(data);
662→
663→    const formattedData = data.map(journal => ({
664→        ...journal,
665→        has_liked: userHasLikedSet.has(journal.id),
666→        has_bookmarked: userHasBookmarkedSet.has(journal.id),
667→        user_reaction: userReactionMap.get(journal.id) || null
668→    }));
669→
670→    const hasMore = data.length > parsedLimit;
671→    const slicedData = hasMore ? formattedData.slice(0, parsedLimit) : formattedData;
