 337→const isPrivateIpv6Address = (ip) => {
 338→    const normalized = ip.toLowerCase();
 339→    return (
 340→        normalized === '::1' ||
 341→        normalized.startsWith('fc') ||
 342→        normalized.startsWith('fd') ||
 343→        normalized.startsWith('fe80:')
 344→    );
 345→};
