 421→const fetchRemoteImageBuffer = async (imageUrl) => {
 422→    const controller = new AbortController();
 423→    const timeout = setTimeout(() => controller.abort(), REMOTE_IMAGE_FETCH_TIMEOUT_MS);
 424→
 425→    try {
 426→        const response = await fetch(imageUrl, {
 427→            method: 'GET',
 428→            redirect: 'follow',
 429→            signal: controller.signal,
 430→            headers: {
 431→                Accept: 'image/*,*/*;q=0.8',
 432→                'Accept-Encoding': 'identity',
 433→                'User-Agent': SHARE_IMAGE_FETCH_USER_AGENT,
 434→            },
 435→        });
 436→
 437→        if (!response.ok) {
 438→            throw new Error(`upstream image status ${response.status}`);
 439→        }
 440→
 441→        const finalUrl = response.url || imageUrl;
 442→        if (!isSafeRemoteImageUrl(finalUrl)) {
 443→            throw new Error('upstream redirected to unsafe url');
 444→        }
 445→
 446→        const contentType = String(response.headers.get('content-type') || '').toLowerCase();
 447→        if (!contentType.startsWith('image/')) {
 448→            throw new Error(`upstream content-type ${contentType || 'unknown'} is not an image`);
 449→        }
 450→        if (contentType.includes('image/svg')) {
 451→            throw new Error('svg images are not used for share previews');
 452→        }
 453→
 454→        const headerContentLength = Number(response.headers.get('content-length'));
 455→        if (Number.isFinite(headerContentLength) && headerContentLength > REMOTE_IMAGE_MAX_BYTES) {
 456→            throw new Error(`upstream content-length exceeds ${REMOTE_IMAGE_MAX_BYTES} bytes`);
 457→        }
 458→
 459→        const arrayBuffer = await response.arrayBuffer();
 460→        const buffer = Buffer.from(arrayBuffer);
 461→
 462→        if (!buffer.length) {
 463→            throw new Error('upstream image is empty');
 464→        }
 465→        if (buffer.length > REMOTE_IMAGE_MAX_BYTES) {
 466→            throw new Error(`upstream image exceeds ${REMOTE_IMAGE_MAX_BYTES} bytes`);
 467→        }
 468→
 469→        return {
 470→            buffer,
 471→            contentType,
 472→            byteLength: buffer.length,
 473→            finalUrl,
 474→        };
 475→    } finally {
 476→        clearTimeout(timeout);
 477→    }
 478→};
