 801→app.get('/share/post/:journalId/image', async (req, res) => {
 802→    const { journalId } = req.params;
 803→    await ensureShareFonts();
 804→    const debugMode = isShareImageDebugRequest(req);
 805→    const debugPayload = {
 806→        ok: false,
 807→        fallback: false,
 808→        journalId,
 809→        stage: 'start',
 810→        reason: '',
 811→        meta: {
 812→            imageCandidateSource: null,
 813→            imageCandidateRaw: null,
 814→            imageCandidateResolved: null,
 815→            upstreamFinalUrl: null,
 816→            upstreamContentType: null,
 817→            upstreamBytes: null,
 818→            outputBytes: null,
 819→        },
 820→    };
 821→
 822→    const fallbackWithReason = (reason) => {
 823→        debugPayload.ok = false;
 824→        debugPayload.fallback = true;
 825→        debugPayload.stage = 'fallback';
 826→        debugPayload.reason = reason;
 827→        if (debugMode) {
 828→            return sendShareImageDebug(res, debugPayload);
 829→        }
 830→        return res.redirect(302, DEFAULT_OG_IMAGE_URL);
 831→    };
 832→
 833→    try {
 834→        const journal = await getShareJournal(journalId);
 835→        debugPayload.stage = 'journal_loaded';
 836→        if (!journal) {
 837→            return fallbackWithReason('journal_not_found');
 838→        }
 839→
 840→        const shareMeta = buildShareMetaFromJournal(journal);
 841→        debugPayload.stage = 'candidate_extracted';
 842→        debugPayload.meta.imageCandidateSource = shareMeta.imageCandidateSource;
 843→        debugPayload.meta.imageCandidateRaw = shareMeta.imageCandidate;
 844→
 845→        const candidateEvaluation = evaluateShareImageCandidate(shareMeta.imageCandidate);
 846→        debugPayload.meta.imageCandidateResolved = candidateEvaluation.resolvedUrl;
 847→        if (!candidateEvaluation.ok || !candidateEvaluation.resolvedUrl) {
 848→            return fallbackWithReason(candidateEvaluation.reason);
 849→        }
 850→
 851→        const normalizedFallbackUrl = new URL(DEFAULT_OG_IMAGE_URL).toString();
 852→        if (candidateEvaluation.resolvedUrl === normalizedFallbackUrl) {
 853→            return fallbackWithReason('candidate_is_default_fallback');
 854→        }
 855→
 856→        debugPayload.stage = 'fetching_upstream';
 857→        const remoteImage = await fetchRemoteImageBuffer(candidateEvaluation.resolvedUrl);
 858→        debugPayload.stage = 'upstream_loaded';
 859→        debugPayload.meta.upstreamFinalUrl = remoteImage.finalUrl;
 860→        debugPayload.meta.upstreamContentType = remoteImage.contentType;
 861→        debugPayload.meta.upstreamBytes = remoteImage.byteLength;
 862→
 863→        debugPayload.stage = 'converting_image';
 864→        const ogImageBuffer = await convertToOgJpeg(remoteImage.buffer);
 865→        debugPayload.stage = 'converted_image';
 866→        debugPayload.ok = true;
 867→        debugPayload.reason = 'ok';
 868→        debugPayload.meta.outputBytes = ogImageBuffer.length;
 869→
 870→        if (debugMode) {
 871→            return sendShareImageDebug(res, debugPayload);
 872→        }
 873→
 874→        res.set('Content-Type', 'image/jpeg');
 875→        res.set('Cache-Control', 'public, max-age=3600');
 876→        return res.send(ogImageBuffer);
 877→    } catch (err) {
 878→        debugPayload.stage = 'error';
 879→        debugPayload.reason = err?.message || 'unknown_error';
 880→        console.error('share image route error:', err?.message || err);
 881→        return fallbackWithReason(debugPayload.reason);
 882→    }
 883→});
