 21→const getHotScore = (journal) => {
 22→    if(typeof journal?.hot_score === "number"){
 23→        return journal.hot_score;
 24→    }
 25→
 26→    const likes = journal?.like_count?.[0]?.count || 0;
 27→    const comments = journal?.comment_count?.[0]?.count || 0;
 28→    const bookmarks = journal?.bookmark_count?.[0]?.count || 0;
 29→    const views = journal?.views || 0;
 30→
 31→    return (views * 6) + (likes * 3) + (comments * 2) + (bookmarks * 2);
 32→};
